import { type RequestHandler } from 'aether';
import { requireUser, invalidateSession } from '~/lib/auth';
import { ok, err } from '~/lib/result';

/**
 * POST /auth/logout
 * Invalidates the current user session and clears the session cookie.
 */
export const POST: RequestHandler = async ({ req }) => {
  // AI CONTEXT: Auth is always explicit. requireUser must be called first.
  const userResult = await requireUser(req);
  if (userResult.isErr()) {
    return new Response(JSON.stringify(err(userResult.error)), { status: userResult.error.status, headers: { 'Content-Type': 'application/json' } });
  }

  // Invalidate the session and clear the cookie
  const invalidateResult = await invalidateSession(req);

  if (invalidateResult.isErr()) {
    // This case should ideally not happen if requireUser succeeded,
    // but we handle it for robustness.
    return new Response(JSON.stringify(err(invalidateResult.error)), { status: invalidateResult.error.status, headers: { 'Content-Type': 'application/json' } });
  }

  // Return a success response. The invalidateSession function should have
  // already handled clearing the cookie via response headers.
  return new Response(JSON.stringify(ok({ message: 'Logged out successfully' })), {
    status: 200,
    headers: { 'Content-Type': 'application/json' },
  });
};
```

